"""matplotlib.spines — axis spine classes."""

from matplotlib.patches import Patch


class Spine(Patch):
    def __init__(self, axes, spine_type, path, **kwargs):
        super().__init__(**kwargs)
        self.axes = axes
        self.spine_type = spine_type

    def set_position(self, position): pass
    def get_position(self): return ('outward', 0)
    def set_bounds(self, low=None, high=None): pass
    def get_bounds(self): return (0, 1)
    def set_patch_arc(self, center, radius, theta1, theta2): pass
    def set_patch_circle(self, center, radius): pass
    def set_patch_line(self): pass


class Spines:
    def __init__(self, **kwargs):
        self._spines = kwargs

    def __getitem__(self, key):
        return self._spines.get(key, Spine(None, key, None))

    def __getattr__(self, name):
        if name.startswith('_'):
            raise AttributeError(name)
        return self[name]

    def values(self):
        return self._spines.values()

    def keys(self):
        return self._spines.keys()

    def items(self):
        return self._spines.items()

    @classmethod
    def from_dict(cls, d):
        return cls(**d)
